def simple_backtest(prices, signals, initial_capital=100000):
    commission_rate = 0.0003
    equity = initial_capital
    shares = 0
    position_open = False

    for i in range(len(prices) - 1):
        if signals[i] == 1 and not position_open:
            shares = equity * (1 - commission_rate) / prices[i]
            equity = 0
            position_open = True
        elif signals[i] == 0 and position_open:
            equity = shares * prices[i] * (1 - commission_rate)
            shares = 0
            position_open = False
        elif position_open:
            equity = shares * prices[i]

    if position_open:
        equity = shares * prices[-1]
    return round(equity, 2)
